[
  {
    "id": "unauthenticated-nonlocal-bind",
    "severity": "HIGH",
    "category": "security",
    "location": "scripts/ai_agent_bridge/_cli.py:762",
    "description": "The new `serve --openai` command defaults to localhost, but `--host` allows binding the unauthenticated proxy to any interface and then passes requests directly to local agent CLIs that run with the user's environment and credentials. That contradicts the documented localhost-only boundary and makes `--host 0.0.0.0` an accidental remote code/cost/credential exposure surface. If non-local binding is supported at all, it should require explicit authentication and prominent opt-in naming; otherwise reject hosts other than loopback."
  },
  {
    "id": "unbounded-request-body-to-agent-cli",
    "severity": "MEDIUM",
    "category": "dos-surface",
    "location": "scripts/ai_agent_bridge/openai_proxy.py:300",
    "description": "The chat completions endpoint accepts unbounded `messages` and arbitrary extra request fields, then eagerly flattens all message content into a single prompt before invoking a subprocess. A large local HTTP request can consume substantial memory/CPU during validation and flattening, and for Gemini/Claude/Hermes the prompt is placed directly in argv, which can also exceed OS argument limits. Add explicit request-size/message-count/content-length limits and return a structured 4xx error before constructing the prompt or spawning a backend."
  },
  {
    "id": "unbounded-concurrent-backend-spawns",
    "severity": "MEDIUM",
    "category": "dos-surface",
    "location": "scripts/ai_agent_bridge/openai_proxy.py:312",
    "description": "Every chat completion request synchronously spawns a potentially heavy agent CLI with a default 120-second timeout, but the proxy has no concurrency limit, queue, cancellation policy, or per-client throttling. Even on localhost, a misbehaving OpenAI client retry loop can fan out many Codex/Gemini/Claude/Hermes processes and exhaust CPU, memory, file descriptors, or provider quota. Gate backend execution with a small bounded semaphore/queue and return 429/503 when saturated."
  },
  {
    "id": "stream-true-silently-ignored",
    "severity": "MEDIUM",
    "category": "spec-compliance",
    "location": "scripts/ai_agent_bridge/openai_proxy.py:284",
    "description": "The request model allows unknown OpenAI fields but the endpoint silently ignores `stream: true` and still returns a non-streaming JSON response. Many OpenAI-compatible clients switch parsing paths when they request streaming and will expect SSE chunks, so this creates hard-to-debug client failures. Since Phase 1 is intentionally non-streaming, the proxy should explicitly parse `stream` and reject `true` with a clear OpenAI-style 400 error."
  }
]

